 13→function screenToModel(screenX, screenY, viewport, svgRect) {
 14→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 15→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 16→  return { x, y };
 17→}
 18→
 19→function useSketchTool() {
 20→  const { dispatch: sketchDispatch, getLayer } = useSketch();
 21→  const {
 22→    activeTool, viewport, snapEnabled, selectedId, selectedType,
 23→    toolState, activeLayerId, dispatch: editorDispatch,
 24→  } = useSketchEditor();
 25→
 26→  const ctx = {
 27→    dispatch: sketchDispatch,
 28→    editorDispatch,
 29→    getLayer,
 30→    activeLayerId,
 31→    viewport,
 32→    snapEnabled,
 33→    selectedId,
 34→    selectedType,
 35→  };
 36→
 37→  switch (activeTool) {
 38→    case 'rectangle':
 39→      return createRectangleHandler(ctx);
 40→    case 'line':
 41→      return createLineHandler(ctx);
 42→    case 'select':
 43→    default:
 44→      return createSketchSelectHandler(ctx);
 45→  }
 46→}
