 48→export default function SketchCanvas() {
 49→  const svgRef = useRef(null);
 50→  const isPanning = useRef(false);
 51→  const lastPanPos = useRef({ x: 0, y: 0 });
 52→  const spaceHeld = useRef(false);
 53→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 54→
 55→  const { project } = useSketch();
 56→  const {
 57→    activeTool, selectedId, toolState,
 58→    viewport, showGrid, activeLayerId, statusMessage,
 59→    dispatch: editorDispatch,
 60→  } = useSketchEditor();
 61→
 62→  const tool = useSketchTool();
 63→
 64→  const getModelPos = useCallback((e) => {
 65→    const rect = svgRef.current.getBoundingClientRect();
 66→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 67→  }, [viewport]);
 68→
 69→  const handleMouseDown = useCallback((e) => {
 70→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 71→      isPanning.current = true;
 72→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 73→      e.preventDefault();
 74→      return;
 75→    }
 76→
 77→    const modelPos = getModelPos(e);
 78→    tool.onMouseDown(modelPos, e, toolState);
 79→  }, [getModelPos, tool, toolState]);
 80→
 81→  const handleMouseMove = useCallback((e) => {
 82→    if (isPanning.current) {
 83→      const dx = e.clientX - lastPanPos.current.x;
 84→      const dy = e.clientY - lastPanPos.current.y;
 85→      editorDispatch({ type: 'PAN', dx, dy });
 86→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 87→      return;
 88→    }
 89→
 90→    const modelPos = getModelPos(e);
 91→    setCursorPos(modelPos);
 92→    tool.onMouseMove(modelPos, e, toolState, selectedId);
 93→  }, [getModelPos, tool, toolState, selectedId, editorDispatch]);
 94→
 95→  const handleMouseUp = useCallback((e) => {
 96→    if (isPanning.current) {
 97→      isPanning.current = false;
 98→      return;
 99→    }
100→
101→    const modelPos = getModelPos(e);
102→    tool.onMouseUp(modelPos, e, toolState);
103→  }, [getModelPos, tool, toolState]);
104→
105→  const handleWheel = useCallback((e) => {
106→    e.preventDefault();
107→    const rect = svgRef.current.getBoundingClientRect();
108→    const mouseX = e.clientX - rect.left;
109→    const mouseY = e.clientY - rect.top;
110→
111→    const direction = e.deltaY < 0 ? 1 : -1;
112→    const factor = direction > 0 ? SKETCH_ZOOM_FACTOR : 1 / SKETCH_ZOOM_FACTOR;
113→    const newZoom = Math.max(SKETCH_MIN_ZOOM, Math.min(SKETCH_MAX_ZOOM, viewport.zoom * factor));
114→
115→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
116→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
117→
118→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
119→  }, [viewport, editorDispatch]);
120→
121→  // Keyboard shortcuts
122→  useEffect(() => {
123→    const handleKeyDown = (e) => {
124→      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
125→
126→      if (e.key === ' ') {
127→        spaceHeld.current = true;
128→        e.preventDefault();
129→        return;
130→      }
131→
132→      if (e.key === 'Escape') {
133→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
134→        return;
135→      }
136→
137→      if (!e.ctrlKey && !e.metaKey) {
138→        const toolKey = SKETCH_TOOL_SHORTCUTS[e.key.toLowerCase()];
139→        if (toolKey) {
140→          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
141→          return;
142→        }
143→      }
144→
145→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
146→        tool.onKeyDown(e, toolState, selectedId);
147→        return;
148→      }
149→
150→      tool.onKeyDown(e, toolState, selectedId);
151→    };
152→
153→    const handleKeyUp = (e) => {
154→      if (e.key === ' ') {
155→        spaceHeld.current = false;
156→      }
157→    };
158→
159→    window.addEventListener('keydown', handleKeyDown);
160→    window.addEventListener('keyup', handleKeyUp);
161→    return () => {
162→      window.removeEventListener('keydown', handleKeyDown);
163→      window.removeEventListener('keyup', handleKeyUp);
164→    };
165→  }, [editorDispatch, selectedId, tool, toolState]);
166→
167→  // Prevent context menu & attach wheel listener
168→  useEffect(() => {
169→    const svg = svgRef.current;
170→    if (!svg) return;
171→    const prevent = (e) => e.preventDefault();
172→    svg.addEventListener('contextmenu', prevent);
173→    svg.addEventListener('wheel', handleWheel, { passive: false });
174→    return () => {
175→      svg.removeEventListener('contextmenu', prevent);
176→      svg.removeEventListener('wheel', handleWheel);
177→    };
178→  }, [handleWheel]);
179→
180→  // Status message auto-clear
181→  useEffect(() => {
182→    if (!statusMessage) return undefined;
183→    const timer = window.setTimeout(() => {
184→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
185→    }, 2500);
186→    return () => window.clearTimeout(timer);
187→  }, [statusMessage, editorDispatch]);
188→
189→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor(toolState);
190→  const zoomPercent = Math.round(viewport.zoom * 1000);
191→
192→  // Collect all visible shapes with their layer IDs
193→  const visibleShapes = [];
194→  for (const layer of project.layers) {
195→    if (!layer.visible) continue;
196→    for (const shape of layer.shapes) {
197→      visibleShapes.push({ shape, layerId: layer.id });
198→    }
199→  }
200→
201→  // Rectangle preview
202→  const rectPreview = activeTool === 'rectangle' && toolState.startPos && toolState.currentPos
203→    ? {
204→        x: Math.min(toolState.startPos.x, toolState.currentPos.x),
205→        y: Math.min(toolState.startPos.y, toolState.currentPos.y),
206→        width: Math.abs(toolState.currentPos.x - toolState.startPos.x),
207→        height: Math.abs(toolState.currentPos.y - toolState.startPos.y),
208→      }
209→    : null;
210→
211→  // Line preview
212→  const linePreview = activeTool === 'line' && toolState.startPos && toolState.currentPos
213→    ? { start: toolState.startPos, end: toolState.currentPos }
214→    : null;
215→
216→  return (
217→    <div className={styles.canvasContainer}>
218→      <svg
219→        ref={svgRef}
220→        className={styles.svg}
221→        style={{ cursor }}
222→        onPointerDown={handleMouseDown}
223→        onPointerMove={handleMouseMove}
224→        onPointerUp={handleMouseUp}
225→      >
226→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
227→          {showGrid && <GridRenderer />}
228→
229→          {/* Canvas boundary indicator */}
230→          <rect
231→            x={0}
232→            y={0}
233→            width={project.canvasWidth}
234→            height={project.canvasHeight}
235→            fill="none"
236→            stroke="var(--color-border)"
237→            strokeWidth={2}
238→            vectorEffect="non-scaling-stroke"
239→            strokeDasharray="8 4"
240→            style={{ pointerEvents: 'none' }}
241→          />
242→
243→          {/* Rendered shapes */}
244→          {visibleShapes.map(({ shape }) => (
245→            <ShapeRenderer
246→              key={shape.id}
247→              shape={shape}
248→              isSelected={shape.id === selectedId}
249→              zoom={viewport.zoom}
250→            />
251→          ))}
252→
253→          {/* Rectangle draw preview */}
254→          {rectPreview && (
255→            <rect
256→              x={rectPreview.x}
257→              y={rectPreview.y}
258→              width={rectPreview.width}
259→              height={rectPreview.height}
260→              fill="none"
261→              stroke="var(--color-workspace-sketch, #B8860B)"
262→              strokeWidth={2}
263→              vectorEffect="non-scaling-stroke"
264→              strokeDasharray="6 3"
265→              style={{ pointerEvents: 'none' }}
266→            />
267→          )}
268→
269→          {/* Line draw preview */}
270→          {linePreview && (
271→            <line
272→              x1={linePreview.start.x}
273→              y1={linePreview.start.y}
274→              x2={linePreview.end.x}
275→              y2={linePreview.end.y}
276→              stroke="var(--color-workspace-sketch, #B8860B)"
277→              strokeWidth={2}
278→              vectorEffect="non-scaling-stroke"
279→              strokeDasharray="6 3"
280→              style={{ pointerEvents: 'none' }}
281→            />
282→          )}
283→        </g>
284→      </svg>
285→
286→      {/* Status bar */}
287→      <div className={styles.statusBar} role="status" aria-live="polite">
288→        <span className={styles.statusCoords}>X: {Math.round(cursorPos.x)} mm</span>
289→        <span className={styles.statusCoords}>Y: {Math.round(cursorPos.y)} mm</span>
290→        <span className={styles.statusContext}>Zoom: {zoomPercent}%</span>
291→        <span className={styles.statusTool}>{activeTool}</span>
292→        {activeLayerId && (
293→          <span className={styles.statusContext}>
294→            Layer: {project.layers.find((l) => l.id === activeLayerId)?.name || 'Unknown'}
295→          </span>
296→        )}
297→      </div>
298→
299→      {/* Toast notifications */}
300→      {statusMessage && (
301→        <div className={styles.toast}>
302→          {statusMessage}
303→          <div className={styles.toastProgress} />
304→        </div>
305→      )}
306→    </div>
307→  );
308→}
